// All constants — optimizer should fold to literals
let base = 100;
let multiplier = 5;
let result = base * multiplier;
print result;

// Tests ADD / SUB / MUL / DIV opcodes
let x = 20;
let y = 4;
let a = x + y;
let b = x - y;
let c = x * y;
let d = x / y;
print d;

// MOD opcode test — cycle counter / bucket assignment
let items = 17;
let buckets = 5;
let bucket_id = items mod buckets;
print bucket_id;

// ABS opcode — absolute value of a negative number
let temperature = neg 15;
let magnitude = abs(temperature);
print magnitude;

// SQ opcode — square of a number
let side = 7;
let area = sq(side);
print area;

// NEG opcode — negate a variable
let profit = 200;
let loss = neg profit;
let net = profit + loss;
print net;

// Sequential dependency chain — tests copy propagation
let a = 1;
let b = a + 2;
let c = b + 3;
let d = c + 4;
let result = d * 2;
print result;

// Celsius to Fahrenheit: F = (C * 9 / 5) + 32
let celsius = 25;
let scaled = celsius * 9;
let divided = scaled / 5;
let fahrenheit = divided + 32;
print fahrenheit;

// kills * bonus - penalty
let kills = 15;
let bonus = 10;
let penalty = 25;
let raw = kills * bonus;
let score = raw - penalty;
print score;

// Multiply by 2 simulates logical left shift
let byte = 1;
let sh1 = byte * 2;
let sh2 = sh1 * 2;
let sh3 = sh2 * 2;
let sh4 = sh3 * 2;
print sh4;

